from agent import *from models.products import *def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://www.itpro.com/reviews'), process_revlist, dict())def process_revlist(data, context, session):    strip_namespace(data)    page = data.xpath('//div[@class="flexi-pagination"]/span/text()').string()    if not page or not page.isdigit() or int(page) != context.get('page', 1):        return    revs = data.xpath('//ul[contains(@class, "listing__list")]/li//a')    for rev in revs:        name = rev.xpath('.//h2/text()').string() . split(' review')[0]        url = rev.xpath('@href').string()        session.queue(Request(url), process_review, dict(name=name, url=url))    next_page = int(page) + 1    next_url = 'https://www.itpro.com/reviews/page/' + str(next_page)    session.queue(Request(next_url), process_revlist, dict(page=next_page))def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = data.xpath('//div[@id="article-body"]//a[contains(@rel, "sponsored")]/@href').string() or context['url']    product.ssid = context['url'].split('/')[-1]    product.category = 'Tech'    review = Review()    review.title = data.xpath('//h1[@class="header__title"]/text()').string()    review.url = context['url']    review.ssid = product.ssid    review.type = 'pro'    date = data.xpath('//time[@class="relative-date"]/@datetime').string()    if date:        review.date = date.split('T')[0]    author = data.xpath('//a[@rel="author"]').first()    if author:        author_name = author.xpath('text()').string()        author_url = author.xpath('@href').string()        if author_name and author_url:            author_ssid = author_url.split('/')[-1]            review.authors.append(Person(name=author_name, ssid=author_ssid, profile_url=author_url))    pros = data.xpath('//div[@class="procon__pros"]//li/p/text()').strings()    for pro in pros:        review.add_property(type='pros', value=pro)    cons = data.xpath('//div[@class="procon__cons"]//li/p/text()').strings()    for con in cons:        review.add_property(type='cons', value=con)    grade_overall = data.xpath('count(//div[@class="rating"]//span[@class="rating__star"])')    if grade_overall and grade_overall > 0:        review.grades.append(Grade(type='overall', value=grade_overall, best=5.0))    summary = data.xpath('//div[@class="news-article"]//p[contains(@class, "header")]//text()').string(multiple=True)    if summary and summary.strip():        review.add_property(type='summary', value=summary.strip())    conclusion = data.xpath('//div[@id="article-body"]/p[preceding-sibling::h2[contains(., "Is it worth it")]]//text()').string(multiple=True)    if conclusion and conclusion.strip():        review.add_property(type='conclusion', value=conclusion.strip())    excerpt = data.xpath('//div[@id="article-body"]/p[not(preceding-sibling::h2[contains(., "Is it worth it")])]//text()').string(multiple=True)    if excerpt and excerpt.strip():        review.add_property(type='excerpt', value=excerpt.strip())        product.reviews.append(review)        session.emit(product)